var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"시스템 온라인.","JPN":"システムオンライン。","ENG":"System online.","TWN":"系統上線。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"최고 관리자의 접속을 확인.","JPN":"最高管理者のアクセスを確認。","ENG":"Supreme Administrator access verified.","TWN":"確認最高管理者連接。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"현재 장비 정밀화율 95%, 튜닝 바이너리 삽입.","JPN":"現在の装備精密化率95％、チューニングバイナリーを挿入。","ENG":"Gear precision at 95%. Inserting Tuning Binary.","TWN":"當前裝備精密化率95％，插入二進位系統。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"버스터 코어 레긴 & 파프닐의 정밀화를 위한 재기동 대기 중.","JPN":"バスターコア[レギン＆ファフニール]の\\n精密化のための再起動待機中。","ENG":"Standing by to re-initialize the Buster Cores, Regin and Fafnir, for precision.","TWN":"為了爆裂核心雷金＆帕夫尼爾的精密化，再啟動待機中。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"최종 기동 당시 기록된 전투를 시뮬레이팅하기 위한 승인을 기다립니다.","JPN":"最終起動当時に記録された戦闘を\\nシミュレーションするため、承認をお待ちしています。","ENG":"Awaiting authorization for the simulation of the final battle recorded in the previous session.","TWN":"為了模擬最後一次啟動時的戰鬥記錄，等待許可中"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"승인하지. 복원을 시작하도록.","JPN":"承認する。復元を開始するように。","ENG":"Authorized. Commence recovery.","TWN":"批准，開始復原。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"관리자의 허가를 확인. 전투 기록과 장비의 동기화를 시작합니다.","JPN":"管理者の許可を確認。\\n戦闘記録と装備の同期を開始します。","ENG":"Administrator authorization confirmed. Synchronizing the combat logs and the gear.","TWN":"確認管理者許可，開始同步戰鬥記錄和裝備。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님, 정말 하실 건가요?","JPN":"師匠、本当にやるつもりですか？","ENG":"Are you sure you want to do this, Master?","TWN":"師父，真的要這樣做嗎？"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"테라사이드 시스템의 최종목적은 결국 클리포트 인자의 복제체를 만드는 거다.","JPN":"テラサイドシステムの最終目標は、\\nクリフォト・ファクターの複製体を作ることだ。","ENG":"The ultimate goal of System Terraside is to replicate the Qliphoth Factors.","TWN":"特拉賽德系統的最終目標是創造出逆卡巴拉因子的複製體。"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이대로 두면 대량으로 생산해 낸 클리포트 레플리카 인자로 놈이 무슨 짓을 할지 몰라.","JPN":"このまま放っておけば、大量に生産した\\nレプリカ・クリフォト・ファクターで奴が何をしでかすかわからない。","ENG":"If we let them be, they will raise all hell with the mass-produced Qliphoth Replica Factors.","TWN":"再這樣下去，不知道那些傢伙們會拿大量生產出來的逆卡巴拉複製因子做些什麼事情。"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이미 연쇄반응이 시작된 이상, 사태를 정리하려면 어느 정도 손해를 감수하더라도 압도적인 힘으로 끊어내 버리는 게 상책이다.","JPN":"すでに連鎖反応が始まってしまった以上、この事態を収束するためには\\nある程度のリスクを覚悟のうえで、圧倒的な力で\\n断ち切るしかないだろう。","ENG":"The chain reaction has already started. It's best to put it all to rest quickly with overwhelming strength, although it means we'll have to take some damage.","TWN":"在連鎖反應已經開始的情況下，想要控制事態，就得承受一定的損失，用壓倒性的力量結束這一切才是上策。"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그리고 내가 아니면......","JPN":"それに、私以外に……","ENG":"Besides, I'm the only one left here...","TWN":"還有，如果不是我……"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이곳엔 이미 5종 침식체급으로 성장해 버린 저 <color=#ffd34c>테라사이드의 가마솥</color>을 파괴할 자가 없으니까.","JPN":"すでに第5種侵食体級に成長してしまった\\n<color=#ffd34c>テラサイドの釜</color>を破壊できる者は、ここにはいない。","ENG":"who's capable of destroying the <color=#ffd34c>Cauldron of the Terraside</color>, which has become as threatening as a Category 5 C.O.","TWN":"這裡沒有人能夠破壞已經成長為第5級侵蝕體的<color=#ffd34c>特拉賽德之釜</color>。"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구구절절한 이야기를 늘어놓고 계시지만 제가 보기에는 그저 미나 양을 구하러 가기 위한 변명으로밖에는 들리지 않는군요.","JPN":"さっきから長々と話していますが、私にはミナさんを\\n救いに行くための口実にしか聞こえませんね。","ENG":"Every single word you say sound like a mere excuse you're making up to go save Mina.","TWN":"您說了這麼多，在我看來也不過是為了去救米娜小姐的藉口而已。"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 나유빈을 요격하는 대신 여기로 온 것 자체가......","JPN":"そもそも、イチノセ・カオルを迎撃せずに\\nここに来ていること自体が……","ENG":"You coming here instead of launching an attack against Na Yubin was actually—","TWN":"說到底，您不迎擊羅瑜斌，反而來到這裡這件事本身……"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"함교!","JPN":"艦橋！","ENG":"Bridge!","TWN":"艦橋！"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"강하한다! 램프도어 개방!","JPN":"降下する！ ランプドア開放！","ENG":"I'm going down! Open the ramp door!","TWN":"我要降落了！打開艙門！"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};